sql:
SELECT public_key, private_key
FROM key_pairs
WHERE app_id = 'PRE_REGISTRATION';

external_knowledge:
- Active key pairs refer to key pairs that are currently in use and have not expired or been deactivated; 
- Key pair rotation refers to the process of updating or replacing a key pair with a new one; 
- The responsible role is the role assigned to the user who created the key pair; 
- The latest activity description is the description of the most recent activity performed on the key pair.

sql:
SELECT COUNT(*) AS active_key_pairs_count
   FROM key_pairs
   WHERE is_active = 1;

SELECT app_name
FROM applications
WHERE is_active = 1;

SELECT key_pair_id, rotation_frequency, next_rotation_date
FROM key_pair_rotation
WHERE rotation_frequency = 'MONTHLY';

SELECT public_key, private_key
   FROM key_pairs
   WHERE is_active = 1 AND key_validity_duration > 30;
